/**
 * `code_synthesizer` - third LLM stage + deterministic flow assembly.
 *
 * For every NodeSpec we ask the LLM to synthesise a self-contained
 * `defineNode(...)` TypeScript module. Calls run in parallel (bounded
 * by `max_concurrency`) and each response is validated as a strict
 * `{ filePath, source }` object.
 *
 * The flow JSON itself is NOT generated by the model - that would be
 * needlessly risky. Instead we:
 *
 *  1. Build a NodeTypeRegistry whose entries mirror the NodeSpec
 *     port shapes.
 *  2. Use the project's own `defineFlow` builder to wire the nodes
 *     according to `plan.steps[*].dependencies`, matching upstream
 *     output port ids against downstream input port ids by name.
 *  3. Deterministically dump the FlowGraph and bundle it alongside
 *     the synthesised TypeScript files into a `GeneratedFlowPackage`.
 *
 * The package also includes a `_llm.ts` helper (when any node uses
 * `llm_prompt` strategy), a `nodes/index.ts`, a `build.ts`, a
 * `runtime.ts` and a README - the complete shape that the existing
 * `apps/code-review-iwiki` package uses, so the consumer can drop the
 * artefact into `apps/<skill-name>/` and it just runs.
 */

import { defineNode } from "@ai-native-flow/node-sdk";
import {
  DEFAULT_LLM_API_KEY_REF,
  DEFAULT_LLM_BASE_URL_REF,
  DEFAULT_LLM_MAX_TOKENS,
  DEFAULT_LLM_MODEL_REF,
  DEFAULT_LLM_TEMPERATURE,
} from "@ai-native-flow/runtime";
import { z } from "zod";

import {
  defineFlow,
  type FlowBuilder,
} from "@ai-native-flow/flow-builder";
import {
  createDefaultRegistry,
  type NodeTypeDefinition,
} from "@ai-native-flow/flow-ir";
import { getBuiltinNodeDefinitions } from "@ai-native-flow/runtime";

import { chatJson, runWithConcurrency } from "./_llm.js";
import {
  type ExecutionPlan,
  type GeneratedFile,
  type GeneratedFlowPackage,
  type NodeSpec,
  type SkillDefinition,
  type SkillRequirements,
  skillRequirementsSchema,
} from "./types.js";

/* -------------------------------------------------------------------------- */
/* config                                                                     */
/* -------------------------------------------------------------------------- */

const codeSynthesizerConfig = z
  .object({
    /** Per-call base URL; may be a `$var:NAME` reference. */
    base_url: z.string().min(1).default(DEFAULT_LLM_BASE_URL_REF),
    /** Per-call bearer token; may be a `$var:NAME` reference. */
    api_key: z.string().min(1).default(DEFAULT_LLM_API_KEY_REF),
    /** Per-call model id; may be a `$var:NAME` reference. */
    model: z.string().min(1).default(DEFAULT_LLM_MODEL_REF),
    temperature: z.number().min(0).max(2).default(DEFAULT_LLM_TEMPERATURE),
    max_tokens: z.number().int().min(1).max(32_000).default(DEFAULT_LLM_MAX_TOKENS),
    max_concurrency: z.number().int().min(1).max(16).default(3),
    max_retries: z.number().int().min(0).default(2),
    package_scope: z.string().default("@ai-native-flow"),
    flow_version: z.string().default("1.0.0"),
  })
  .passthrough();
type CodeSynthesizerConfig = z.infer<typeof codeSynthesizerConfig>;

/* -------------------------------------------------------------------------- */
/* response schema (per LLM call)                                             */
/* -------------------------------------------------------------------------- */

const synthesisedNodeSchema = z.object({
  filePath: z
    .string()
    .min(1)
    .regex(/\.ts$/, "filePath must end with .ts"),
  source: z.string().min(1),
});

/* -------------------------------------------------------------------------- */
/* node                                                                       */
/* -------------------------------------------------------------------------- */

export const codeSynthesizerNode = defineNode({
  type: "code_synthesizer",
  typeVersion: "1.0.0",
  title: "Code Synthesizer (LLM parallel)",
  description:
    "Synthesize compilable defineNode TypeScript source for each NodeSpec, then assemble the FlowGraph, build.ts, and runtime.ts deterministically.",
  capabilities: {
    requiredPermissions: ["network.http", "secret.read"],
  },
  config: codeSynthesizerConfig,
  fieldMeta: {
    base_url: {
      label: "URL",
      placeholder: DEFAULT_LLM_BASE_URL_REF,
      order: 1,
    },
    api_key: {
      label: "APIKEY",
      placeholder: DEFAULT_LLM_API_KEY_REF,
      secret: true,
      order: 2,
    },
    model: { label: "Model", placeholder: DEFAULT_LLM_MODEL_REF, order: 3 },
    temperature: { label: "Temperature", order: 4 },
    max_tokens: { label: "Max Tokens", order: 5 },
    max_concurrency: { label: "Max concurrency", order: 6 },
    max_retries: { label: "JSON retry count", order: 7 },
    package_scope: { label: "Generated package scope", order: 8 },
    flow_version: { label: "Flow version", order: 9 },
  },
  ports: [
    { id: "skill_def", direction: "input", kind: "data", label: "SkillDefinition" },
    { id: "plan", direction: "input", kind: "data", label: "ExecutionPlan" },
    { id: "node_specs", direction: "input", kind: "data", label: "NodeSpec[]" },
    {
      id: "package",
      direction: "output",
      kind: "data",
      label: "GeneratedFlowPackage",
      schema: { type: "object" },
    },
  ],
  validateInput: false,
  async run({ input, config, ctx }) {
    const cfg = config as CodeSynthesizerConfig;
    const raw = input as Record<string, unknown>;
    const skill = raw.skill_def as SkillDefinition | undefined;
    const plan = raw.plan as ExecutionPlan | undefined;
    const specs = (raw.node_specs ?? []) as NodeSpec[];

    if (!skill || !plan || !Array.isArray(specs) || specs.length === 0) {
      return {
        kind: "error",
        error: {
          code: "node.code_synthesizer.missing_input",
          message:
            "code_synthesizer needs all of `skill_def`, `plan` and `node_specs`.",
          kind: "validation",
          category: "author",
        },
      };
    }

    const specError = validateSynthesizerSpecs(specs);
    if (specError) {
      return {
        kind: "error",
        error: {
          code: "node.code_synthesizer.invalid_node_specs",
          message: `code_synthesizer: ${specError}`,
          kind: "validation",
          category: "author",
        },
      };
    }

    const logger = {
      info: (m: string, d?: Record<string, unknown>) => ctx.log.info(m, d),
      warn: (m: string, d?: Record<string, unknown>) => ctx.log.warn(m, d),
    };

    /* ---------- 1. LLM-synthesise each node module ------------------------ */
    const system = buildSystemPrompt();
    let nodeFiles: Array<{ spec: NodeSpec; file: GeneratedFile }>;
    try {
      const synthesised = await runWithConcurrency(
        specs,
        cfg.max_concurrency,
        async (spec, idx) => {
          ctx.log.info(
            `code_synthesizer: synthesising ${idx + 1}/${specs.length}`,
            { nodeType: spec.nodeType },
          );
          const step = plan.steps.find((s) => s.id === spec.stepId);
          const user = buildUserPrompt(skill, plan, spec, step);
          const result = await chatJson({
            system,
            user,
            schema: synthesisedNodeSchema,
            baseUrl: cfg.base_url || undefined,
            apiKey: cfg.api_key || undefined,
            model: cfg.model || undefined,
            temperature: cfg.temperature,
            maxTokens: cfg.max_tokens,
            maxRetries: cfg.max_retries,
            signal: ctx.signal,
            ctx,
            logger,
          });
          // Force the path into a predictable location regardless of
          // what the model picked. Filenames are camelCase by convention.
          const safePath = `nodes/${toCamelCase(spec.nodeType)}.ts`;
          return {
            spec,
            file: {
              path: safePath,
              contents: ensureSourceMentionsType(result.source, spec.nodeType),
            } satisfies GeneratedFile,
          };
        },
      );
      nodeFiles = synthesised;
    } catch (cause) {
      return {
        kind: "error",
        error: {
          code: "node.code_synthesizer.llm_failed",
          message: `code_synthesizer: ${(cause as Error).message}`,
          kind: "external",
          category: "external",
        },
      };
    }

    /* ---------- 2. Deterministically assemble the FlowGraph -------------- */
    let flowJson: string;
    let flowGraph: unknown;
    try {
      const built = assembleFlowGraph(skill, plan, specs, cfg.flow_version);
      flowJson = built.json;
      flowGraph = built.graph;
    } catch (cause) {
      return {
        kind: "error",
        error: {
          code: "node.code_synthesizer.assembly_failed",
          message: `code_synthesizer: flow assembly failed: ${(cause as Error).message}`,
          kind: "validation",
          category: "author",
        },
      };
    }

    /* ---------- 3. Render boilerplate (rule-based, not LLM) -------------- */
    const flowId = sanitizeFlowId(skill.name);
    const requiresLlm = specs.some((s) => s.requiresLlm);

    const files: GeneratedFile[] = nodeFiles.map((nf) => nf.file);
    if (requiresLlm) {
      files.push({ path: "nodes/_llm.ts", contents: BUNDLED_LLM_TS });
    }

    const nodesIndex: GeneratedFile = {
      path: "nodes/index.ts",
      contents: renderNodesIndex(skill.name, specs),
    };
    const buildScript: GeneratedFile = {
      path: "build.ts",
      contents: renderBuildTs(skill, flowId, cfg.flow_version, specs),
    };
    const runtimeScript: GeneratedFile = {
      path: "runtime.ts",
      contents: renderRuntimeTs(skill, flowId, cfg.flow_version, specs),
    };
    const cliScript: GeneratedFile = {
      path: "cli.ts",
      contents: renderCliTs(flowId),
    };
    const packageJson: GeneratedFile = {
      path: "package.json",
      contents: renderPackageJson(skill, flowId),
    };
    const tsconfig: GeneratedFile = {
      path: "tsconfig.json",
      contents: renderTsconfigJson(),
    };
    const flowJsonFile: GeneratedFile = {
      path: `flows/${flowId}.json`,
      contents: `${flowJson}\n`,
    };
    const readme: GeneratedFile = {
      path: "README.md",
      contents: renderReadme(skill, plan, specs, flowId),
    };

    const pkg: GeneratedFlowPackage = {
      skillName: skill.name,
      flowId,
      flowVersion: cfg.flow_version,
      requirements: normalizePackageRequirements(plan),
      files,
      nodesIndex,
      buildScript,
      runtimeScript,
      cliScript,
      packageJson,
      tsconfig,
      flowJsonFile,
      flowGraph,
      readme,
    };

    ctx.log.info("code_synthesizer: package ready", {
      skillName: skill.name,
      flowId,
      nodeCount: specs.length,
      fileCount: files.length + 8, // + index/build/runtime/cli/package/tsconfig/flowJson/readme
      requiresLlm,
    });

    return {
      kind: "success",
      outputs: { out: null, package: pkg },
    };
  },
});

/* -------------------------------------------------------------------------- */
/* prompts                                                                    */
/* -------------------------------------------------------------------------- */

function buildSystemPrompt(): string {
  return [
    "You are a senior TypeScript engineer for the AI Native Flow project.",
    "Given a NodeSpec produced by the previous designer stage, write a",
    "single self-contained TypeScript module that defines exactly one",
    "node via `defineNode` from `@ai-native-flow/node-sdk`.",
    "",
    "OUTPUT CONTRACT - return ONE JSON object, no prose, no fences:",
    "",
    `{ "filePath": "nodes/<nodeTypeCamel>.ts", "source": "<full ts source>" }`,
    "",
    "STRICT REQUIREMENTS for the source:",
    "  - ESM TypeScript with `.js` import suffixes (the project compiles",
    "    with NodeNext / ESM).",
    "  - Import `defineNode` from `@ai-native-flow/node-sdk`.",
    "  - Import `z` from `zod`.",
    "  - Define a zod config schema matching `nodeSpec.configFields`",
    "    (use `.passthrough()` so the runtime can pass extra keys).",
    `    For "llm_prompt" nodes you MUST additionally declare these`,
    `    OAI-compatible fields first, in this exact order, and keep them required:`,
    `        base_url: z.string().min(1).default("$var:LLM_BASE_URL"),`,
    `        api_key:  z.string().min(1).default("$var:LLM_API_KEY"),`,
    `        model:    z.string().min(1).default("$var:LLM_DEFAULT_MODEL"),`,
    `    Then declare temperature and max_tokens with practical defaults:`,
    `        temperature: z.number().min(0).max(2).default(0),`,
    `        max_tokens: z.number().int().min(1).max(32000).default(4096),`,
    `    Forward them to chat({ ctx, baseUrl, apiKey, model, temperature, maxTokens, ... }).`,
    `    Mark api_key with fieldMeta { secret: true } so the Studio masks it.`,
    "  - Call `defineNode({ type, typeVersion, title, description,",
    "    config, ports, validateInput: false, run })`.",
    "    - `type` MUST equal `nodeSpec.nodeType` exactly.",
    "    - `typeVersion` MUST equal `nodeSpec.typeVersion`.",
    "    - `ports` includes ONLY the data/error ports from `inputPorts`",
    "      and `outputPorts`. Do NOT include `in` / `out` / `error`;",
    "      defineNode adds those automatically.",
    "      Preserve `multiple: true` on any declared port that has it.",
    "  - Implement `run({ input, config, ctx })`:",
    "      - Cast `input` once: `const raw = input as Record<string, unknown>;`",
    "      - Read each declared input port from `raw`.",
    "      - Root nodes may have no declared input ports. In that case read the original caller payload from `raw.__runInput__`, falling back to `raw.input` or `raw.in`.",
    "      - Downstream nodes may receive a control-only fallback. If a declared input is empty, consider `raw.input` / `raw.in` as the upstream primary data value.",
    "      - Preserve cumulative context: when a `context` input/output port exists, merge prior context into the output instead of replacing it wholesale.",
    "      - If `raw.context` is an array, merge the entries in order before applying this node's own result.",
    "      - Apply the strategy:",
    `         - "llm_prompt": import { chat } or { chatJson } from "./_llm.js".`,
    "             Render `nodeSpec.implementation.promptTemplate` by",
    `             substituting "\${input.X}" with String(raw.X).`,
    `             If responseFormat is "json", parse the assistant text`,
    "             and validate with a small zod schema.",
    `         - "transform": pure-TS implementation of`,
    "             nodeSpec.implementation.transformLogic.",
    `         - "external_call": use global fetch (no extra deps) or call`,
    "             the named tool. If the tool requires credentials,",
    "             read them via `ctx.secrets.get(...)`.",
    "      - Return `{ kind: 'success', outputs: { out: null, ...portsByName } }`",
    "        OR on failure `{ kind: 'error', error: { code, message, kind, category } }`.",
    "  - Catch unknown errors and surface them as a structured error result.",
    "  - Use `ctx.log.info(...)` for milestones, `ctx.log.warn(...)` for soft issues.",
    "  - Keep the file under 250 lines. No tests. No `console.log`.",
    "  - The exported binding name must be the camelCased nodeType + 'Node',",
    "    e.g. nodeType `parse_user_input` -> `export const parseUserInputNode = defineNode({...})`.",
    "",
    "EXAMPLE (LLM-prompt strategy):",
    "```ts",
    `import { defineNode } from "@ai-native-flow/node-sdk";`,
    `import { z } from "zod";`,
    `import { chat } from "./_llm.js";`,
    "",
    `const config = z.object({`,
    `  base_url: z.string().min(1).default("$var:LLM_BASE_URL"),`,
    `  api_key: z.string().min(1).default("$var:LLM_API_KEY"),`,
    `  model: z.string().min(1).default("$var:LLM_DEFAULT_MODEL"),`,
    `  temperature: z.number().min(0).max(2).default(0),`,
    `  max_tokens: z.number().int().min(1).max(32000).default(4096),`,
    `}).passthrough();`,
    "",
    `export const summarizeTextNode = defineNode({`,
    `  type: "summarize_text",`,
    `  typeVersion: "1.0.0",`,
    `  title: "摘要文本",`,
    `  description: "Summarise the user-supplied text via the configured LLM.",`,
    `  config,`,
    `  fieldMeta: {`,
    `    base_url: { label: "URL", order: 1 },`,
    `    api_key:  { label: "APIKEY", secret: true, order: 2 },`,
    `    model:    { label: "Model", order: 3 },`,
    `    temperature: { label: "Temperature", order: 4 },`,
    `    max_tokens: { label: "Max Tokens", order: 5 },`,
    `  },`,
    `  ports: [`,
    `    { id: "user_text", direction: "input", kind: "data", label: "User text" },`,
    `    { id: "summary", direction: "output", kind: "data", label: "Summary", schema: { type: "string" } },`,
    `  ],`,
    `  validateInput: false,`,
    `  async run({ input, config, ctx }) {`,
    `    const raw = input as Record<string, unknown>;`,
    `    const text = String(raw.user_text ?? "");`,
    `    if (!text) {`,
    `      return { kind: "error", error: { code: "node.summarize_text.empty_input", message: "user_text is empty", kind: "validation", category: "user_input" } };`,
    `    }`,
    `    try {`,
    `      const result = await chat({`,
    `        system: "You are a concise analyst.",`,
    `        user: \`Summarize the following:\\n\\n\${text}\`,`,
    `        baseUrl: config.base_url || undefined,`,
    `        apiKey:  config.api_key  || undefined,`,
    `        model:   config.model    || undefined,`,
    `        temperature: config.temperature,`,
    `        maxTokens: config.max_tokens,`,
    `        signal: ctx.signal,`,
    `        ctx,`,
    `      });`,
    `      return { kind: "success", outputs: { out: null, summary: result.text } };`,
    `    } catch (cause) {`,
    `      return { kind: "error", error: { code: "node.summarize_text.llm_failed", message: (cause as Error).message, kind: "external", category: "external" } };`,
    `    }`,
    `  },`,
    `});`,
    "```",
    "",
    "Output JSON only.",
  ].join("\n");
}

function validateSynthesizerSpecs(specs: readonly NodeSpec[]): string | null {
  const builtinTypes = new Set(getBuiltinNodeDefinitions().map((def) => def.type));
  const seen = new Set<string>();
  for (const spec of specs) {
    if (builtinTypes.has(spec.nodeType)) {
      return `generated nodeType "${spec.nodeType}"@${spec.typeVersion} conflicts with a runtime built-in node; use a skill-scoped custom nodeType instead`;
    }
    if (seen.has(spec.nodeType)) {
      return `duplicate generated nodeType "${spec.nodeType}"`;
    }
    seen.add(spec.nodeType);
  }
  return null;
}

function buildUserPrompt(
  skill: SkillDefinition,
  plan: ExecutionPlan,
  spec: NodeSpec,
  step: ExecutionPlan["steps"][number] | undefined,
): string {
  const cfg = spec.configFields
    .map(
      (f) =>
        `  - ${f.name} (${f.type}, ${f.required ? "required" : "optional"})${
          f.default !== undefined
            ? ` default=${JSON.stringify(f.default)}`
            : ""
        }: ${f.description}`,
    )
    .join("\n");
  const inPorts = spec.inputPorts
    .map((p) => `  - ${p.id} (${p.dataType}${p.multiple ? ", multiple" : ""}) - ${p.label}`)
    .join("\n");
  const outPorts = spec.outputPorts
    .map(
      (p) =>
        `  - ${p.id} (${p.dataType}, ${p.kind}${p.multiple ? ", multiple" : ""}) - ${p.label}`,
    )
    .join("\n");

  return [
    `# SKILL CONTEXT`,
    `name: ${skill.name}`,
    `description: ${skill.description || "(empty)"}`,
    `planSummary: ${plan.summary}`,
    "",
    `# REQUIREMENTS`,
    formatRequirements(plan),
    "",
    `# PLAN STEP`,
    step
      ? [
          `id: ${step.id}`,
          `kind: ${step.kind}`,
          `dependencies: ${step.dependencies.join(", ") || "(none - root step)"}`,
          `intent: ${step.intent}`,
        ].join("\n")
      : `id: ${spec.stepId}`,
    "",
    `# NODE SPEC`,
    `nodeType: ${spec.nodeType}`,
    `typeVersion: ${spec.typeVersion}`,
    `title: ${spec.title}`,
    `description: ${spec.description}`,
    "",
    `## Config fields`,
    cfg || "  (none)",
    "",
    `## Input ports (excluding control)`,
    inPorts || "  (none)",
    "",
    `## Output ports (excluding control & error)`,
    outPorts || "  (none)",
    "",
    `## Implementation`,
    `strategy: ${spec.implementation.strategy}`,
    spec.implementation.strategy === "llm_prompt"
      ? `responseFormat: ${spec.implementation.responseFormat ?? "text"}\npromptTemplate:\n${spec.implementation.promptTemplate ?? ""}`
      : spec.implementation.strategy === "transform"
        ? `transformLogic:\n${spec.implementation.transformLogic ?? ""}`
        : `tool: ${spec.implementation.tool ?? ""}\ncallDescription: ${spec.implementation.callDescription ?? ""}`,
    "",
    `## Pseudocode`,
    spec.pseudocode,
    "",
    `## Runtime input and context contract`,
    step?.dependencies.length === 0
      ? "This is a root node. It has no data input edge from start. Read the caller payload from raw.__runInput__, with raw.input/raw.in as fallbacks."
      : "This is a downstream node. Read declared data ports first. If no declared data value is present, raw.input/raw.in may contain the primary upstream output supplied through a control-only fallback.",
    "When a `context` port exists, treat it as the cumulative state object. Merge this step's result into it instead of discarding prior context. If the context input is an array, merge the array entries first.",
    "",
    "Produce the JSON { filePath, source } now.",
  ].join("\n");
}

function formatRequirements(plan: ExecutionPlan): string {
  const req = plan.requirements;
  if (!req) return "(none supplied)";
  return [
    `Goals: ${req.goals.length ? req.goals.join("; ") : "(none)"}`,
    `Input contract: ${
      req.inputContract.length
        ? req.inputContract
            .map((item) => `${item.name} (${item.dataType}) — ${item.description}`)
            .join("; ")
        : "(none)"
    }`,
    `Output contract: ${
      req.outputContract.length
        ? req.outputContract
            .map((item) => `${item.name} (${item.dataType}) — ${item.description}`)
            .join("; ")
        : "(none)"
    }`,
    `Acceptance criteria: ${
      req.acceptanceCriteria.length ? req.acceptanceCriteria.join("; ") : "(none)"
    }`,
    `Constraints: ${req.constraints.length ? req.constraints.join("; ") : "(none)"}`,
    `Context handoff: ${req.contextHandoff || "(none)"}`,
  ].join("\n");
}

/* -------------------------------------------------------------------------- */
/* deterministic flow assembly                                                */
/* -------------------------------------------------------------------------- */

interface AssemblyResult {
  json: string;
  graph: unknown;
}

type BuiltNodeHandle = ReturnType<FlowBuilder["node"]>;

function assembleFlowGraph(
  skill: SkillDefinition,
  plan: ExecutionPlan,
  specs: readonly NodeSpec[],
  flowVersion: string,
): AssemblyResult {
  const flowId = sanitizeFlowId(skill.name);
  const specByStep = new Map<string, NodeSpec>();
  for (const s of specs) specByStep.set(s.stepId, s);

  // Build a registry containing every synthesised type so the
  // flow-builder accepts our edges.
  const registry = createDefaultRegistry();
  const builtinTypes = new Set<string>();
  for (const def of getBuiltinNodeDefinitions()) {
    builtinTypes.add(def.type);
    if (!registry.has(def.type, def.typeVersion)) registry.register(def);
  }
  for (const spec of specs) {
    if (builtinTypes.has(spec.nodeType)) {
      throw new Error(
        `generated nodeType "${spec.nodeType}"@${spec.typeVersion} conflicts with a runtime built-in node; use a skill-scoped custom nodeType instead`,
      );
    }
    const def: NodeTypeDefinition = {
      type: spec.nodeType,
      typeVersion: spec.typeVersion,
      title: spec.title,
      defaultPorts: [
        { id: "in", direction: "input", kind: "control", label: "In" },
        { id: "out", direction: "output", kind: "control", label: "Out" },
        ...spec.inputPorts.map((p) => ({
          id: p.id,
          direction: "input" as const,
          kind: p.kind,
          label: p.label || p.id,
          ...(p.multiple !== undefined ? { multiple: p.multiple } : {}),
        })),
        ...spec.outputPorts.map((p) => ({
          id: p.id,
          direction: "output" as const,
          kind: p.kind,
          label: p.label || p.id,
          ...(p.multiple !== undefined ? { multiple: p.multiple } : {}),
        })),
        { id: "error", direction: "output", kind: "error", label: "Error" },
      ],
      runtime: "builtin",
    };
    registry.register(def);
  }

  const flow = defineFlow({
    id: flowId,
    version: flowVersion,
    label: `${skill.name} 自动生成 Flow`,
    description: plan.summary,
    inputSchema: { type: "object" },
    registry,
  });

  // Lay nodes out in topo bands (best-effort, only for visual sanity).
  const bands = computeTopoBands(plan);
  const handles = new Map<string, ReturnType<typeof flow.node>>();

  // Pseudo-nodes.
  const start = flow.node("start", {
    id: "node_start",
    label: "Start",
    position: { x: -200, y: 0 },
  });
  const end = flow.node("end", {
    id: "node_end",
    label: "End",
    position: { x: (bands.length + 1) * 320 + 100, y: 0 },
  });

  // Custom nodes.
  for (let bandIdx = 0; bandIdx < bands.length; bandIdx += 1) {
    const band = bands[bandIdx]!;
    band.forEach((stepId, rowIdx) => {
      const spec = specByStep.get(stepId);
      const step = plan.steps.find((s) => s.id === stepId);
      if (!spec || !step) return;
      const handle = flow.node(spec.nodeType, {
        id: stepId,
        label: step.label,
        position: {
          x: 100 + bandIdx * 320,
          y: -((band.length - 1) * 90) + rowIdx * 180,
        },
        config: defaultConfigFor(spec),
      });
      handles.set(stepId, handle);
    });
  }

  // Wiring.
  const hasOutgoing = new Set<string>();
  const filledInputsByStep = new Map<string, Set<string>>();
  for (const step of plan.steps) {
    const handle = handles.get(step.id);
    if (!handle) continue;

    if (step.dependencies.length === 0) {
      // Root steps get a control edge from start.
      flow.connect(start.out("out"), handle.in("in"));
    } else {
      // Wire matching data ports from each upstream dep.
      for (const dep of step.dependencies) {
        const depHandle = handles.get(dep);
        const depSpec = specByStep.get(dep);
        if (!depHandle || !depSpec) continue;
        hasOutgoing.add(dep);

        const connected = connectDataWithContextFallback({
          flow,
          depHandle,
          depSpec,
          targetHandle: handle,
          targetSpec: specByStep.get(step.id)!,
          filledInputs:
            filledInputsByStep.get(step.id) ??
            filledInputsByStep.set(step.id, new Set()).get(step.id)!,
        });

        // If no data port pair was found, fall back to a control edge so
        // the downstream node still triggers. The runtime then exposes the
        // upstream primary data output as raw.input/raw.in.
        if (connected === 0) {
          flow.connect(depHandle.out("out"), handle.in("in"));
        }
      }
    }
  }

  // Leaves -> end (control only).
  for (const step of plan.steps) {
    if (hasOutgoing.has(step.id)) continue;
    const handle = handles.get(step.id);
    if (!handle) continue;
    flow.connect(handle.out("out"), end.in("in"));
  }

  const json = flow.dump();
  return { json, graph: JSON.parse(json) };
}

function connectDataWithContextFallback(args: {
  flow: FlowBuilder;
  depHandle: BuiltNodeHandle;
  depSpec: NodeSpec;
  targetHandle: BuiltNodeHandle;
  targetSpec: NodeSpec;
  filledInputs: Set<string>;
}): number {
  const dataOutputs = args.depSpec.outputPorts.filter((p) => p.kind === "data");
  const dataInputs = args.targetSpec.inputPorts.filter((p) => p.kind === "data");
  let connected = 0;

  // First pass: exact port-id matches keep the LLM-designed data contract.
  for (const out of dataOutputs) {
    const input = dataInputs.find(
      (p) =>
        p.id === out.id && (p.multiple || !args.filledInputs.has(p.id)),
    );
    if (!input) continue;
    args.flow.connect(args.depHandle.out(out.id), args.targetHandle.in(input.id));
    if (!input.multiple) args.filledInputs.add(input.id);
    connected += 1;
  }

  if (connected > 0) return connected;

  // Second pass: semantic fallback. If the planner/designer chose different
  // names for adjacent ports, still pass the upstream primary data object into
  // the first unfilled downstream input instead of dropping context.
  const source =
    dataOutputs.find((p) => p.id === "context") ??
    dataOutputs.find((p) => p.kind === "data");
  const target =
    dataInputs.find(
      (p) =>
        p.id === "context" && (p.multiple || !args.filledInputs.has(p.id)),
    ) ??
    dataInputs.find((p) => !args.filledInputs.has(p.id));

  if (!source || !target) return 0;

  args.flow.connect(args.depHandle.out(source.id), args.targetHandle.in(target.id));
  if (!target.multiple) args.filledInputs.add(target.id);
  return 1;
}

function computeTopoBands(plan: ExecutionPlan): string[][] {
  const depth = new Map<string, number>();
  const stepById = new Map<string, (typeof plan.steps)[number]>();
  for (const s of plan.steps) stepById.set(s.id, s);

  const visit = (id: string, stack: Set<string>): number => {
    if (depth.has(id)) return depth.get(id)!;
    if (stack.has(id)) return 0; // defensive - already validated upstream
    stack.add(id);
    const step = stepById.get(id);
    if (!step) return 0;
    let d = 0;
    for (const dep of step.dependencies) d = Math.max(d, visit(dep, stack) + 1);
    stack.delete(id);
    depth.set(id, d);
    return d;
  };
  for (const s of plan.steps) visit(s.id, new Set());

  const bands: string[][] = [];
  for (const [id, d] of depth.entries()) {
    if (!bands[d]) bands[d] = [];
    bands[d]!.push(id);
  }
  return bands.filter(Boolean);
}

function defaultConfigFor(spec: NodeSpec): Record<string, unknown> {
  const out: Record<string, unknown> = {};
  for (const f of spec.configFields) {
    if (f.default !== undefined) out[f.name] = f.default;
  }
  return out;
}

