function renderReadme(
  skill: SkillDefinition,
  plan: ExecutionPlan,
  specs: readonly NodeSpec[],
  flowId: string,
): string {
  const stepsTable = plan.steps
    .map((s) => {
      const sp = specs.find((sp) => sp.stepId === s.id);
      return `| ${s.id} | ${s.kind} | ${sp?.nodeType ?? "?"} | ${s.description} |`;
    })
    .join("\n");
  return [
    `# ${skill.name}`,
    "",
    `> ${skill.description || "(no description)"}`,
    "",
    `This package was generated by \`@ai-native-flow/skill-to-flow\`.`,
    `It converts SKILL.md into a runnable Flow package.`,
    "",
    `## Requirements`,
    "",
    renderRequirementsMarkdown(plan),
    "",
    `## Structure`,
    "",
    `- \`build.ts\` validates the bundled Flow JSON against the generated node registry`,
    `- \`runtime.ts\` exposes a factory for CLI / HTTP / tests`,
    `- \`cli.ts\` runs the generated flow through @ai-native-flow/transport-cli`,
    `- \`package.json\` declares the minimal runnable app package`,
    `- \`tsconfig.json\` enables static TypeScript validation`,
    `- \`flows/${flowId}.json\` contains the generated FlowGraph`,
    `- \`nodes/\` contains ${specs.length} custom nodes`,
    "",
    `## Plan`,
    "",
    plan.summary,
    "",
    `| Step ID | Kind | Node Type | Description |`,
    `|---|---|---|---|`,
    stepsTable,
    "",
    `## 运行`,
    "",
    `\`\`\`bash`,
    `npm install`,
    `tsx build.ts`,
    `npm run typecheck`,
    `tsx cli.ts run ${flowId} --input '{}'`,
    `\`\`\``,
    "",
  ].join("\n");
}

function normalizePackageRequirements(plan: ExecutionPlan): SkillRequirements {
  return skillRequirementsSchema.parse(plan.requirements ?? {});
}

function renderRequirementsMarkdown(plan: ExecutionPlan): string {
  const req = normalizePackageRequirements(plan);
  return [
    `### Goals`,
    renderBulletList(req.goals),
    "",
    `### Input Contract`,
    renderIoList(req.inputContract),
    "",
    `### Output Contract`,
    renderIoList(req.outputContract),
    "",
    `### Acceptance Criteria`,
    renderBulletList(req.acceptanceCriteria),
    "",
    `### Constraints`,
    renderBulletList(req.constraints),
    "",
    `### Context Handoff`,
    "",
    req.contextHandoff || "(none)",
  ].join("\n");
}

function renderBulletList(items: readonly string[]): string {
  if (!items.length) return "- (none)";
  return items.map((item) => `- ${item}`).join("\n");
}

function renderIoList(
  items: ReadonlyArray<{ name: string; dataType: string; description: string }>,
): string {
  if (!items.length) return "- (none)";
  return items
    .map((item) => `- \`${item.name}\` (${item.dataType}): ${item.description}`)
    .join("\n");
}

/* -------------------------------------------------------------------------- */
/* helpers                                                                     */
/* -------------------------------------------------------------------------- */

function nodeBindingName(spec: NodeSpec): string {
  return `${toCamelCase(spec.nodeType)}Node`;
}

function toCamelCase(snake: string): string {
  return snake.replace(/_([a-z0-9])/g, (_, ch: string) => ch.toUpperCase());
}

function pascalCase(snake: string): string {
  const camel = toCamelCase(snake);
  return camel.charAt(0).toUpperCase() + camel.slice(1);
}

function sanitizeFlowId(skillName: string): string {
  return (
    skillName
      .toLowerCase()
      .replace(/[^a-z0-9]+/g, "_")
      .replace(/^_+|_+$/g, "") || "generated_flow"
  );
}

/**
 * Light safety net: if the LLM omitted the type literal we paste it
 * back in as a comment so the linter in `flow_validator` reports a
 * clear hint instead of a generic "type not found" warning.
 */
function ensureSourceMentionsType(source: string, nodeType: string): string {
  if (source.includes(`type: "${nodeType}"`)) return source;
  return `${source}\n\n// skill-to-flow: expected nodeType "${nodeType}" - verify the defineNode call above\n`;
}

