/* -------------------------------------------------------------------------- */
/* bundled _llm.ts (kept in sync with apps/skill-to-flow/nodes/_llm.ts)       */
/* -------------------------------------------------------------------------- */

const BUNDLED_LLM_TS = `/**
 * _llm.ts - chat helper bundled with the generated package.
 *
 * This helper does not hand-roll vendor communication. It delegates to
 * the runtime LlmProvider boundary, whose production implementation uses
 * Vercel AI SDK's OpenAI-compatible provider.
 */
import {
  AiSdkOpenAICompatibleLlmProvider,
  type LlmCompletionRequest,
  type NodeContext,
} from "@ai-native-flow/runtime";

export interface ChatOptions {
  system?: string;
  user: string;
  model?: string;
  temperature?: number;
  baseUrl?: string;
  apiKey?: string;
  maxTokens?: number;
  signal?: AbortSignal;
  ctx: unknown;
  jsonMode?: boolean;
}

export interface ChatResult {
  text: string;
  raw?: unknown;
}

const provider = new AiSdkOpenAICompatibleLlmProvider({
  providerName: "skill-to-flow-generated",
});

function buildPrompt(o: ChatOptions): string {
  const parts: string[] = [];
  if (o.system && o.system.trim()) parts.push(\`System:\\n\${o.system}\`);
  const user = o.jsonMode
    ? \`\${o.user}\\n\\nReturn ONLY one valid JSON object. No prose, no markdown fences.\`
    : o.user;
  parts.push(\`User:\\n\${user}\`);
  return parts.join("\\n\\n");
}

export async function chat(o: ChatOptions): Promise<ChatResult> {
  const request: LlmCompletionRequest = {
    prompt: buildPrompt(o),
    ...(o.model !== undefined ? { model: o.model } : {}),
    temperature: o.temperature ?? 0,
    ...(o.maxTokens !== undefined ? { maxTokens: o.maxTokens } : {}),
    ...(o.baseUrl !== undefined ? { baseUrl: o.baseUrl } : {}),
    ...(o.apiKey !== undefined ? { apiKey: o.apiKey } : {}),
  };
  const result = await provider.complete(request, o.ctx as NodeContext);
  return { text: result.text, raw: result.raw };
}

export async function chatJson<T>(
  o: ChatOptions & { schema: { safeParse: (v: unknown) => { success: boolean; data?: T; error?: { issues: any[] } } }; maxRetries?: number },
): Promise<T> {
  const max = o.maxRetries ?? 2;
  let lastErr = "";
  for (let i = 0; i <= max; i += 1) {
    const userPrompt =
      i === 0
        ? o.user
        : \`\${o.user}\\n\\n---\\nPrevious response failed: \${lastErr}\\nReturn ONLY valid JSON.\`;
    const r = await chat({ ...o, user: userPrompt, jsonMode: true });
    let s = r.text.trim();
    if (s.charCodeAt(0) === 0xfeff) s = s.slice(1);
    const fence = /^\\\`\\\`\\\`(?:json)?\\s*([\\s\\S]*?)\\s*\\\`\\\`\\\`$/i.exec(s);
    if (fence && fence[1]) s = fence[1].trim();
    let parsed: unknown;
    try {
      parsed = JSON.parse(s);
    } catch (e) {
      lastErr = \`parse: \${(e as Error).message}\`;
      continue;
    }
    const c = o.schema.safeParse(parsed);
    if (c.success && c.data !== undefined) return c.data;
    lastErr = c.error
      ? c.error.issues
          .map((iss) => \`\${(iss.path ?? []).join(".")}: \${iss.message}\`)
          .join("; ")
      : "schema mismatch";
  }
  throw new Error(\`chatJson exhausted retries: \${lastErr}\`);
}
`;

